import{_ as a,o as e,c as i,e as s}from"./app-def54fd2.js";const r="/assets/image-20230910171044918-5bb4f734.png",t="/assets/image-20230910171110623-2e98fd51.png",l="/assets/image-20230910171155451-37afa20a.png",c="/assets/image-20230910171212873-a492e213.png",n="/assets/image-20230910171227401-0dc54976.png",d="/assets/image-20230910171256573-ce1b9572.png",p="/assets/image-20230910171317000-c23ad48f.png",h="/assets/image-20230910171339495-1aecc49d.png",o={},_=s('<h1 id="缓存和数据库的一致性问题" tabindex="-1"><a class="header-anchor" href="#缓存和数据库的一致性问题" aria-hidden="true">#</a> 缓存和数据库的一致性问题</h1><p>数据库和缓存（redis）双写数据一致性问题，在高并发的场景下，这个问题尤为严重。</p><p>首先：只要是双写，总会有数据一致性的问题，大多数情况下我们并不是严格要求<strong>缓存+数据库</strong> 必须保持一致性。</p><p>简单数据获取流程：</p><p><img src="'+r+'" alt="image-20230910171044918"></p><h2 id="缓存删除而不是更新" tabindex="-1"><a class="header-anchor" href="#缓存删除而不是更新" aria-hidden="true">#</a> 缓存删除而不是更新</h2><p>其实删除缓存，而不是更新缓存，就是一个 lazy 计算的思想，不要每次都重新做复杂的计算，不管它会不会用到，而是让它到需要被使用的时候再重新计算。</p><p><img src="'+t+'" alt="image-20230910171110623"></p><h2 id="常见的四种方案" tabindex="-1"><a class="header-anchor" href="#常见的四种方案" aria-hidden="true">#</a> 常见的四种方案</h2><ol><li>先更新缓存，再更新数据库</li><li>先更新数据库，再更新缓存</li><li>先删缓存，再更新数据库</li><li>先更新数据库，再删缓存</li></ol><h3 id="先更新缓存-再更新数据库" tabindex="-1"><a class="header-anchor" href="#先更新缓存-再更新数据库" aria-hidden="true">#</a> 先更新缓存，再更新数据库</h3><p><img src="'+l+'" alt="image-20230910171155451"></p><p>此时缓存和数据库中的数据出现不一致，缓存中的数据也就没有了意义。</p><h3 id="先更新数据库-再更新缓存" tabindex="-1"><a class="header-anchor" href="#先更新数据库-再更新缓存" aria-hidden="true">#</a> 先更新数据库，再更新缓存</h3><p><img src="'+c+'" alt="image-20230910171212873"></p><p>数据库是新数据，而缓存是旧数据或者没有数据，出现数据不一致的情况。</p><p><img src="'+n+'" alt="image-20230910171227401"></p><p>步骤说明（图中顺序为请求顺序）：</p><ol><li>请求1：进行到步骤2时出现问题，此时发生了延迟</li><li>请求2：步骤3、4，顺利执行</li><li>请求1：步骤2此时才开始执行。</li><li>请求3：获取缓存内的数据，此时获取到的是请求1写入缓存的数据，此时读取的是旧数据。</li></ol><h3 id="先更新数据库-再删除缓存" tabindex="-1"><a class="header-anchor" href="#先更新数据库-再删除缓存" aria-hidden="true">#</a> 先更新数据库，再删除缓存</h3><p>先更新数据库，再删除缓存。如果删除缓存失败了，那么会导致数据库中是新数据，缓存中是旧数据，数据就出现了不一致。</p><p><img src="'+d+'" alt="image-20230910171256573"></p><h3 id="先删除缓存-再更新数据库" tabindex="-1"><a class="header-anchor" href="#先删除缓存-再更新数据库" aria-hidden="true">#</a> 先删除缓存，再更新数据库</h3><ul><li>数据库更新失败了，那么数据库中是旧数据，缓存中是空的，那么数据不会不一致</li><li>读的时候缓存没有，所以去读了数据库中的旧数据，然后更新到缓存中。</li></ul><p><img src="'+p+'" alt="image-20230910171317000"></p><h3 id="延时双删" tabindex="-1"><a class="header-anchor" href="#延时双删" aria-hidden="true">#</a> 延时双删</h3><p>依旧是<strong>先更新数据库，再删除缓存</strong>，一段时间间隔后再一次删除缓存。</p><p><img src="'+h+'" alt="image-20230910171339495"></p><ul><li>使用 <code>DelayQueue</code>，会随着 JVM 进程的死亡，丢失更新的风险</li><li>使用 <code>MQ</code></li><li>缓存设置有效期</li><li>订阅 Mysql 数据库的 binlog 日志对缓存进行操作</li></ul>',29),m=[_];function g(f,u){return e(),i("div",null,m)}const x=a(o,[["render",g],["__file","缓存和数据库的一致性问题.html.vue"]]);export{x as default};
